phase.opensearch_configuration:
        
from opensearchpy import OpenSearch

# Connect to OpenSearch
client = OpenSearch(
    hosts=[{'host': os.getenv("OPENSEARCH_HOST"), 'port': 443}],
    http_auth=(os.getenv("OPENSEARCH_USER"), os.getenv("OPENSEARCH_PASSWORD")),
    use_ssl=True,
    verify_certs=True
)

# Create index with k-NN configuration
index_body = {
    "settings": {
        "index": {
            "knn": True,
            "knn.algo_param.ef_search": 100
        }
    },
    "mappings": {
        "properties": {
            "embedding": {
                "type": "knn_vector",
                "dimension": 768,
                "method": {
                    "name": "hnsw",
                    "space_type": "cosinesimil",
                    "engine": "nmslib",
                    "parameters": {
                        "ef_construction": 128,
                        "m": 16
                    }
                }
            },
            "text": {"type": "text"},
            "source": {"type": "keyword"},
            "metadata": {"type": "object"}
        }
    }
}

client.indices.create(index="knowledge_base", body=index_body)

phase.opensearch_hybrid_search:
        
def search_opensearch_hybrid(query: str, top_k: int = 5, filters: dict = None):
    """Hybrid search combining vector and keyword search"""
    
    # Generate query embedding
    query_vector = embeddings.embed_query(query)
    
    # Build hybrid query
    search_body = {
        "size": top_k,
        "query": {
            "bool": {
                "should": [
                    {
                        "knn": {
                            "embedding": {
                                "vector": query_vector,
                                "k": top_k
                            }
                        }
                    },
                    {
                        "match": {
                            "text": {
                                "query": query,
                                "boost": 0.3  # Weight keyword search lower
                            }
                        }
                    }
                ]
            }
        }
    }
    
    # Add filters if provided
    if filters:
        search_body["query"]["bool"]["filter"] = [
            {"term": {key: value}} for key, value in filters.items()
        ]
    
    # Execute search
    response = client.search(index="knowledge_base", body=search_body)
    
    # Format results
    results = []
    for hit in response["hits"]["hits"]:
        results.append({
            "text": hit["_source"]["text"],
            "source": hit["_source"]["source"],
            "metadata": hit["_source"]["metadata"],
            "score": hit["_score"]
        })
    
    return results
